    tattva: { en: 'Earth', hi: 'पृथ्वी', sa: 'पृथिवी', mr: 'पृथ्वी', mai: 'पृथ्वी', ta: 'பூமி', te: 'భూమి', gu: 'પૃથ્વી' , bn: 'পৃথিবী', kn: 'ಪೃಥ್ವಿ' },
    gana: { en: 'Rakshasa (Demonic)', hi: 'राक्षस', sa: 'राक्षसः', mr: 'राक्षस', mai: 'राक्षस', ta: 'ராக்ஷச', te: 'రాక్షస', gu: 'રાક્ષસ' , bn: 'রাক্ষস', kn: 'ರಾಕ್ಷಸ' },
